			for _, ch := range word {
				if _, exists := node.children[ch]; !exists {
					node.children[ch] = &TrieNode{children: make(map[rune]*TrieNode)}
				}
				node = node.children[ch]
			}
		}
		return &Trie{root: root}
	}

	// Function to find the longest common prefix between two words
	func lcp(word1, word2 string) int {
		minLen := len(word1)
		if len(word2) < minLen {
			minLen = len(word2)
		}
		for i := 0; i < minLen; i++ {
			if word1[i] != word2[i] {
				return i
			}
		}
		return minLen
	}

	// Build the trie for the original list of words
	trie := buildTrie(words)

	// For each index, simulate removing it and compute the max LCP
	for i := 0; i < n; i++ {
		// Remove the i-th word
		// Compute the max LCP between adjacent words in the modified list
		maxLCP := 0
		for j := 0; j < n-1; j++ {
			if j == i {
				continue
			}
