	type TrieNode struct {
		children map[rune]*TrieNode
	}
	type Trie struct {
		root *TrieNode
	}

	// Function to build a trie from a list of words
	func buildTrie(words []string) *Trie {
		trie := &Trie{
			root: &TrieNode{children: make(map[rune]*TrieNode)},
		}
		for _, word := range words {
			node := trie.root
			for _, ch := range word {
				if _, ok := node.children[ch]; !ok {
					node.children[ch] = &TrieNode{children: make(map[rune]*TrieNode)}
				}
				node = node.children[ch]
			}
		}
		return trie
	}

	// Function to find the longest common prefix between two words
	func lcp(word1, word2 string) int {
		minLen := len(word1)
		if len(word2) < minLen {
			minLen = len(word2)
		}
		for i := 0; i < minLen; i++ {
			if word1[i] != word2[i] {
				return i
			}
		}
		return minLen
	}

	// Function to find the maximum LCP in the array after removing the i-th element
	func maxLCPAfterRemove(words []string, i int) int {
		maxLCP := 0
		for j := 0; j < len(words)-1; j++ {
			if j == i {
				continue
			}
			if j+1 == i {
				continue
			}
			lcpLen := lcp(words[j], words[j+1])
			if lcpLen > maxLCP {
				maxLCP = lcpLen
			}
		}
		return maxLCP
	}

	// For each index, remove it and calculate the maximum LCP
	for i := 0; i < n; i++ {
		result[i] = int64(maxLCPAfterRemove(words, i))
	}

	return result
}
